const byId=(id)=>document.getElementById(id);const sessionStorageKey='atlas-authenticated-session-v1';let session=null;let refreshPromise=null;let conversationId=null;let pilotObjects=[];let workspaceActions=[];let workspaceAwareness=[];let firmEvents=[];let conflictScreening=null;let socialState=null;let emailProviders=[];let emailConnections=[];let accountingSummary=null;let accountingProviders=null;let accountingCmsProviders=[];let accountingCmsConnections=[];let voiceAssistantState=null;let simulatedVoiceCallId=null;let smsState=null;let migrationProviders=[];let migrationConnections=[];let migrationBatches=[];let migrationPayload=null;let activeMatter=null;let matterEvents=[];let activeCollection=null;let activeView='dashboard';byId('apiBase').value=window.location.origin;
function installSmsPanel(){const panel=document.createElement('section');panel.id='smsConnection';panel.className='proposal hidden';panel.innerHTML='<div class="section-head"><div><strong>Atlas call & text assistant</strong><p class="muted">Receive texts through the same Communications workspace. Atlas acknowledges receipt, prepares review work and draft replies, and requires a person to approve substantive sends.</p></div><span id="smsConnectionStatus" class="pill">Checking</span></div><form id="smsConfigurationForm"><label><input id="smsAutoAcknowledgement" type="checkbox" checked> Send the approved automated receipt acknowledgment</label><label>Automated acknowledgment<textarea id="smsAcknowledgement" maxlength="600">This is Atlas, the firm’s automated assistant. Your message was received for staff review. This text does not create an attorney-client relationship. Do not text urgent or highly sensitive information.</textarea></label><button class="primary" type="submit">Save text assistant</button><div id="smsConfigurationError" class="error"></div></form><div class="section-head"><h3>Test fictional inbound text</h3></div><form id="smsSimulationForm"><label>Fictional text<input id="smsSimulationBody" required maxlength="1600" value="Please call me about an update on my case"></label><button type="submit">Receive fictional text</button></form><div class="section-head"><h3>Compose outbound draft</h3></div><form id="smsDraftForm"><div class="grid"><label>Recipient number<input id="smsDraftTo" type="tel" required maxlength="40" placeholder="+1 555 010 2026"></label><label>Draft message<textarea id="smsDraftBody" required maxlength="1600"></textarea></label></div><button type="submit">Create draft for approval</button></form><div class="section-head"><h3>Text drafts awaiting approval</h3></div><div id="smsDraftList" class="object-grid"></div><p id="smsStatusMessage" class="muted"></p>';byId('collectionForm').before(panel);}installSmsPanel();
function installSecurityPanel(){const panel=document.createElement('section');panel.id='securitySettings';panel.className='card';panel.innerHTML='<div class="section-head"><div><span class="pill">Trust & security</span><h2>Account protection</h2></div><span id="mfaStatus" class="command-console-badge">Checking</span></div><p class="muted">Protect your account with an authenticator app and single-use recovery codes. Atlas encrypts the authenticator secret and stores only hashes of recovery codes.</p><form id="mfaEnrollForm"><label>Current password<input id="mfaPassword" type="password" required autocomplete="current-password"></label><button class="primary" type="submit">Set up authenticator MFA</button></form><section id="mfaEnrollment" class="proposal hidden"><strong>Save this authenticator setup now</strong><p class="muted">Add the secret to your authenticator app, save the recovery codes offline, then enter a current six-digit code.</p><label>Authenticator secret<input id="mfaSecret" readonly></label><label>Recovery codes<textarea id="mfaRecoveryCodes" readonly></textarea></label><form id="mfaConfirmForm"><label>Current authenticator code<input id="mfaConfirmCode" inputmode="numeric" autocomplete="one-time-code" required maxlength="6"></label><button class="primary" type="submit">Confirm and enable MFA</button></form></section><form id="mfaDisableForm" class="hidden"><div class="grid"><label>Current password<input id="mfaDisablePassword" type="password" required autocomplete="current-password"></label><label>Authenticator or recovery code<input id="mfaDisableCode" required autocomplete="one-time-code" maxlength="24"></label></div><button class="danger" type="submit">Disable MFA and sign out</button></form><p id="mfaMessage" class="muted"></p><div id="firmSecurityAdmin"><div class="section-head"><div><span class="pill">Firm administrators</span><h2>Security activity</h2></div><button id="refreshSecurity" type="button">Refresh</button></div><p class="muted">Review sign-in activity and active, rotated, expired, or revoked sessions across this firm.</p><div id="securityEventList" class="object-grid"></div><div class="section-head"><h2>Firm sessions</h2><span id="firmSessionCount" class="pill"></span></div><div id="firmSessionList" class="object-grid"></div><form id="firmSignOutForm"><label>Emergency sign-out confirmation<input id="firmSignOutConfirmation" required placeholder="Type SIGN OUT ALL"></label><button class="danger" type="submit">Sign out every firm user</button></form><p id="firmSecurityMessage" class="muted"></p></div>';byId('view-settings').append(panel);}installSecurityPanel();
function installFirmPolicyControls(){const section=document.createElement('section');section.className='proposal';section.innerHTML='<div class="section-head"><div><span class="pill">Firm access policy</span><h2>Require MFA for this firm</h2></div><span id="firmMfaPolicyStatus" class="command-console-badge">Checking</span></div><p class="muted">When enabled, active members without MFA can sign in only to reach account protection. Atlas blocks every firm workspace operation until enrollment is complete.</p><form id="firmMfaPolicyForm"><label><input id="firmMfaRequired" type="checkbox"> Require every active firm member to use MFA</label><button class="primary" type="submit">Save firm security policy</button></form>';byId('firmSecurityAdmin').prepend(section);}installFirmPolicyControls();
function installFirmExportControls(){const section=document.createElement('section');section.className='card';section.innerHTML='<div class="section-head"><div><span class="pill">Data portability</span><h2>Export firm data</h2></div><span class="command-console-badge">Administrator only</span></div><p class="muted">Download a verifiable JSON copy of this firm’s canonical objects, relationships, timeline, audits, membership metadata, and reviewed intelligence. Passwords, sessions, MFA secrets, connector credentials, and encryption keys are never included.</p><form id="firmExportForm"><label>Export confirmation<input id="firmExportConfirmation" required autocomplete="off" placeholder="Type EXPORT FIRM DATA"></label><button class="primary" type="submit">Create secure export</button></form><p id="firmExportMessage" class="muted"></p>';byId('view-settings').append(section);}installFirmExportControls();
function installCryptoAccountingPanel(){const section=document.createElement('section');section.id='cryptoAccounting';section.className='card';section.innerHTML='<div class="section-head"><div><span class="pill">Non-custodial digital assets</span><h2>Crypto payments</h2></div><span id="cryptoServiceStatus" class="command-console-badge">Checking</span></div><p class="muted">Accept an approved stablecoin directly into a firm-controlled public wallet. Atlas creates payment instructions and verifies the blockchain transaction before recording payment; Atlas never holds wallet keys, seed phrases, or client funds.</p><div class="grid"><form id="cryptoAccountForm"><h3>Connect receiving address</h3><label>Network and asset<select id="cryptoProvider" required></select></label><label>Firm public wallet address<input id="cryptoAddress" required autocomplete="off" placeholder="0x…"></label><button class="primary" type="submit">Add receiving address</button></form><form id="cryptoRequestForm"><h3>Create invoice payment request</h3><label>Unpaid invoice<select id="cryptoInvoice" required></select></label><label>Receiving address<select id="cryptoReceivingAccount" required></select></label><label>Amount in USD (optional)<input id="cryptoAmount" type="number" min="0.01" step="0.01" placeholder="Full outstanding balance"></label><button class="primary" type="submit">Create crypto request</button></form></div><p id="cryptoMessage" class="muted"></p><div class="section-head"><h3>Receiving addresses</h3></div><div id="cryptoAccountList" class="object-grid"></div><div class="section-head"><h3>Payment requests and confirmations</h3></div><div id="cryptoRequestList" class="object-grid"></div>';byId('accountingStatus').before(section);}installCryptoAccountingPanel();
function installHostedCheckoutPanel(){const section=document.createElement('section');section.id='hostedCheckout';section.className='card';section.innerHTML='<div class="section-head"><div><span class="pill">Secure checkout</span><h2>Collect ACH or card payment</h2></div><span id="checkoutStatus" class="command-console-badge">Checking</span></div><p class="muted">Create a processor-hosted payment page for an unpaid invoice. The client enters bank or card details with the processor; Atlas never receives or stores them.</p><form id="checkoutForm"><div class="grid"><label>Invoice<select id="checkoutInvoice" required></select></label><label>Payment method<select id="checkoutRail"><option value="ach">ACH bank payment</option><option value="card">Debit or credit card</option></select></label><label>Payment processor<select id="checkoutProvider" required></select></label><label>Amount in USD (optional)<input id="checkoutAmount" type="number" min="0.01" step="0.01" placeholder="Full outstanding balance"></label></div><button class="primary" type="submit">Create secure payment link</button><div id="checkoutResult" class="proposal hidden"></div><div id="checkoutError" class="error"></div></form>';byId('cryptoAccounting').before(section);}installHostedCheckoutPanel();
function installQuickBooksAccountingPanel(){const section=document.createElement('section');section.id='quickBooksAccounting';section.className='card';section.innerHTML='<div class="section-head"><div><span class="pill">Connected financial system</span><h2>QuickBooks Online</h2></div><span id="quickBooksStatus" class="command-console-badge">Checking</span></div><p class="muted">Connect through Intuit’s secure consent screen. Atlas never asks for a QuickBooks password and imports financial records read-only into this firm’s canonical digital twin.</p><div class="suggestions"><button id="quickBooksConnect" class="primary" type="button">Connect QuickBooks</button><button id="quickBooksSync" type="button">Sync finances now</button><button id="quickBooksDisconnect" type="button">Disconnect</button></div><p id="quickBooksMessage" class="muted"></p><section class="metrics" aria-label="QuickBooks imported financial summary"><div class="metric"><strong id="quickBooksRecords">—</strong><span>Imported records</span></div><div class="metric"><strong id="quickBooksReceivable">—</strong><span>QBO receivable</span></div><div class="metric"><strong id="quickBooksPayments">—</strong><span>QBO payments</span></div><div class="metric"><strong id="quickBooksExpenses">—</strong><span>QBO bills &amp; purchases</span></div></section><div class="section-head"><h3>Recent imported finances</h3><span id="quickBooksLastSync" class="pill">Not connected</span></div><div id="quickBooksEntryList" class="object-grid"></div>';byId('hostedCheckout').before(section);}installQuickBooksAccountingPanel();
const collectionConfigs={email:{title:'Email',label:'Email subject',dimension:'operation',type:'incoming_email',readOnly:true},calendar:{title:'Calendar',label:'Calendar event',dimension:'operation',type:'deadline',readOnly:true},clients:{title:'Clients',label:'Client name',dimension:'client',type:'client'},documents:{title:'Documents',label:'Document title',dimension:'document',type:'document'},communications:{title:'Communications',label:'Communication subject',dimension:'operation',type:'communication'},tasks:{title:'Tasks',label:'Task title',dimension:'operation',type:'task'},deadlines:{title:'Deadlines',label:'Deadline title',dimension:'operation',type:'deadline'}};
function shouldShowTwinDock(){return true;}
function submitChatOnEnter(inputId,formId){const input=byId(inputId);const form=byId(formId);input.addEventListener('keydown',(event)=>{if(event.key==='Enter'&&!event.shiftKey&&!event.isComposing){event.preventDefault();form.requestSubmit();}});}
function persistSession(){if(!session?.token||!session?.refreshToken||!session?.workspaceId)return;sessionStorage.setItem(sessionStorageKey,JSON.stringify({base:session.base,token:session.token,refreshToken:session.refreshToken,workspaceId:session.workspaceId}));}
function clearStoredSession(){sessionStorage.removeItem(sessionStorageKey);}
async function refreshSession(){if(!session?.refreshToken)throw new Error('Your Atlas session has expired. Sign in again.');if(!refreshPromise)refreshPromise=(async()=>{const response=await fetch(`${session.base}/v1/auth/refresh`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({refreshToken:session.refreshToken})});const body=await response.json();if(!response.ok)throw new Error(body.error?.message??'Your Atlas session has expired. Sign in again.');session.token=body.data.accessToken;session.refreshToken=body.data.refreshToken;persistSession();return session;})().finally(()=>{refreshPromise=null;});return refreshPromise;}
async function request(path,options={},allowRefresh=true){const response=await fetch(`${session.base}${path}`,{...options,headers:{'content-type':'application/json',...(session.token?{authorization:`Bearer ${session.token}`}:{})}});const body=await response.json();if(!response.ok&&response.status===401&&allowRefresh&&session?.refreshToken&&!path.startsWith('/v1/auth/')){try{await refreshSession();return request(path,options,false);}catch(error){resetSignedOutUi();throw error;}}if(!response.ok){const code=body.error?.code;const providerStatus=body.error?.details?.status;const suffix=code?` [${code}${providerStatus?` · provider ${providerStatus}`:''}]`:'';throw new Error(`${body.error?.message??`Atlas returned ${response.status}`}${suffix}`);}return body.data;}
function escape(value){const node=document.createElement('span');node.textContent=String(value??'');return node.innerHTML;}
function caseLink(matter,label=matter?.title){const link=document.createElement('a');link.className='case-link';link.href=`#case/${encodeURIComponent(matter.id)}`;link.dataset.caseId=matter.id;link.textContent=String(label??matter.title);link.addEventListener('click',(event)=>{event.preventDefault();void openMatter(matter);});return link;}
function appendCaseLinkedText(container,value){const text=String(value??'');const matters=pilotObjects.filter(item=>item.dimension==='matter'&&item.title).sort((a,b)=>b.title.length-a.title.length);let remaining=text;while(remaining){let selected=null;let index=-1;for(const matter of matters){const candidate=remaining.toLowerCase().indexOf(matter.title.toLowerCase());if(candidate<0)continue;if(index<0||candidate<index||(candidate===index&&matter.title.length>selected.title.length)){selected=matter;index=candidate;}}if(!selected){container.append(document.createTextNode(remaining));break;}if(index)container.append(document.createTextNode(remaining.slice(0,index)));container.append(caseLink(selected,remaining.slice(index,index+selected.title.length)));remaining=remaining.slice(index+selected.title.length);}}
function casePill(prefix,matter,fallback='Firm-wide'){const pill=document.createElement('span');pill.className='pill';if(prefix)pill.append(document.createTextNode(prefix));if(matter){if(prefix)pill.append(document.createTextNode(' · '));pill.append(caseLink(matter));}else if(fallback){if(prefix)pill.append(document.createTextNode(' · '));pill.append(document.createTextNode(fallback));}return pill;}
function matterForEvent(event){const direct=pilotObjects.find(object=>object.id===event.parentObjectId);if(direct?.dimension==='matter')return direct;const matterId=direct?.parentObjectId??direct?.state?.matterId??event.relatedObjectIds?.find(id=>pilotObjects.some(object=>object.id===id&&object.dimension==='matter'));return workspaceMatter(matterId);}
function eventName(event){return String(event.type??'firm.event').replaceAll('_',' ').replaceAll('.',' · ');}
function eventSearchText(event){const object=pilotObjects.find(item=>item.id===event.parentObjectId);const matter=matterForEvent(event);return [event.type,event.source,event.actorId,object?.title,matter?.title,JSON.stringify(event.data??{})].filter(Boolean).join(' ');}
function appendEventRow(list,event){const row=document.createElement('article');row.className='event-row';const marker=document.createElement('span');marker.className='event-marker';marker.setAttribute('aria-hidden','true');const body=document.createElement('div');const heading=document.createElement('h3');heading.textContent=eventName(event);const object=pilotObjects.find(item=>item.id===event.parentObjectId);const description=document.createElement('p');if(object?.dimension==='matter'){description.append(caseLink(object),document.createTextNode(` · ${object.type}`));}else if(object){appendCaseLinkedText(description,`${object.title} · ${object.type}`);}else{description.textContent='Firm-wide event';}const meta=document.createElement('div');meta.className='event-meta';const matter=matterForEvent(event);meta.append(casePill(event.source??'Atlas',matter,'Firm-wide'));const occurred=new Date(event.occurredAt??event.createdAt);const time=document.createElement('time');time.dateTime=event.occurredAt??event.createdAt??'';time.textContent=Number.isNaN(occurred.getTime())?'Time unavailable':occurred.toLocaleString();meta.append(time);body.append(heading,description,meta);row.append(marker,body);list.append(row);}
function renderFirmEvents(){const query=normalized(byId('firmEventSearch')?.value??'');const newest=[...firmEvents].sort((a,b)=>String(b.occurredAt??b.createdAt??'').localeCompare(String(a.occurredAt??a.createdAt??'')));const homeList=byId('homeEventList');homeList.replaceChildren();newest.slice(0,12).forEach(event=>appendEventRow(homeList,event));byId('homeEventStatus').textContent=newest.length?`Showing the ${Math.min(12,newest.length)} most recent of ${newest.length} firm event${newest.length===1?'':'s'}.`:'No firm events have been recorded yet.';if(!newest.length)homeList.innerHTML='<div class="empty">New firm events will appear here automatically.</div>';const filtered=newest.filter(event=>!query||normalized(eventSearchText(event)).includes(query));const fullList=byId('firmEventList');fullList.replaceChildren();filtered.forEach(event=>appendEventRow(fullList,event));byId('firmEventCount').textContent=`${filtered.length} event${filtered.length===1?'':'s'}`;byId('firmEventStatus').textContent=query?`${filtered.length} of ${newest.length} events match this filter.`:`${newest.length} canonical event${newest.length===1?'':'s'} across the firm.`;if(!filtered.length)fullList.innerHTML='<div class="empty">No firm events match this filter.</div>';}
async function loadFirmEvents(){byId('homeEventStatus').textContent='Loading firm events…';byId('firmEventStatus').textContent='Loading canonical events…';try{firmEvents=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/events`);renderFirmEvents();}catch(error){firmEvents=[];byId('homeEventStatus').textContent=error.message;byId('firmEventStatus').textContent=error.message;byId('firmEventCount').textContent='Unavailable';}}
function renderConflictAlerts(){const list=byId('conflictAlertList');list.replaceChildren();const result=conflictScreening;if(!result)return;byId('conflictAlertCount').textContent=result.alertCount?`${result.alertCount} review`:'Clear';byId('conflictAlertStatus').textContent=`Atlas screened ${result.partyCount} known part${result.partyCount===1?'y':'ies'} across ${result.matterCount} open case${result.matterCount===1?'':'s'} and authorized firm records.`;if(!result.alerts.length){const clear=document.createElement('div');clear.className='conflict-clear';clear.innerHTML='<strong>No potential name matches detected</strong><div>This result will update automatically as cases and firm records change.</div>';list.append(clear);return;}for(const alert of result.alerts){const card=document.createElement('article');card.className='conflict-alert';card.dataset.status=alert.status;card.append(casePill('Potential conflict',workspaceMatter(alert.matterId),'Case unavailable'));const heading=document.createElement('h3');heading.textContent=`${alert.partyName} appears elsewhere in the firm twin`;const summary=document.createElement('p');summary.className='muted';summary.textContent=`${alert.matchCount} matching record${alert.matchCount===1?'':'s'} found. Attorney review is required.`;const matches=document.createElement('ul');matches.className='conflict-match-list';for(const match of alert.matches){const row=document.createElement('li');const related=workspaceMatter(match.matterId);if(related){row.append(caseLink(related),document.createTextNode(` · ${match.objectType} · matched ${match.matchedField}`));}else{appendCaseLinkedText(row,`${match.objectTitle} · ${match.objectType} · matched ${match.matchedField}`);}matches.append(row);}const warning=document.createElement('small');warning.className='muted';warning.textContent=alert.disclaimer;card.append(heading,summary,matches,warning);list.append(card);}}
async function loadConflictAlerts(){byId('conflictAlertCount').textContent='Scanning';byId('conflictAlertStatus').textContent='Atlas is comparing case parties with authorized records throughout this firm’s digital twin.';try{conflictScreening=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/conflicts`);renderConflictAlerts();}catch(error){conflictScreening=null;byId('conflictAlertCount').textContent='Unavailable';byId('conflictAlertStatus').textContent=error.message;}}
function socialTopics(){return [...new Set(byId('socialTopics').value.split(/\n/).map(value=>value.trim()).filter(Boolean))];}
function selectedSocialNetworks(){return [...document.querySelectorAll('[data-social-network]:checked')].map(input=>input.dataset.socialNetwork);}
function renderSocial(){const configuration=socialState?.configuration;const enabled=Boolean(configuration?.state?.enabled);byId('socialEnabled').checked=enabled;document.querySelectorAll('[data-social-network]').forEach(input=>{input.checked=Boolean(configuration?.state?.networks?.includes(input.dataset.socialNetwork));});byId('socialTopics').value=(configuration?.state?.topics??[]).join('\n');byId('socialCadence').innerHTML='<option value="manual">Only when requested</option>';byId('socialCadence').value='manual';byId('socialTone').value=configuration?.state?.tone??'Professional and informative';byId('socialStatusBadge').textContent=enabled?'Suggestions enabled':'Opt in required';const providerList=byId('socialProviderList');providerList.replaceChildren();for(const provider of socialState?.providers??[]){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">Drafting available · publishing off</span><h3>${escape(provider.label)}</h3><p class="muted">A separate OAuth authorization is required before any future account connection. Atlas never asks for the social password.</p>`;providerList.append(card);}const draftList=byId('socialDraftList');draftList.replaceChildren();for(const draft of socialState?.drafts??[]){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">Internal draft · not published</span><h3>${escape(draft.title)}</h3><p></p><small>${escape((draft.state?.networks??[]).join(', ')||'No channel selected')}</small>`;card.querySelector('p').textContent=draft.state?.content??'';draftList.append(card);}byId('socialDraftCount').textContent=`${socialState?.drafts?.length??0} draft${socialState?.drafts?.length===1?'':'s'}`;if(!draftList.children.length)draftList.innerHTML='<div class="empty">Approved social suggestions will remain here as internal drafts.</div>';}
async function loadSocial(){byId('socialStatusBadge').textContent='Loading';try{socialState=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/social-media`);renderSocial();}catch(error){socialState=null;byId('socialStatusBadge').textContent='Unavailable';byId('socialConfigurationError').textContent=error.message;}}
function parsedMatterParties(){return [...new Set(byId('matterParties').value.split(/[\n;]/).map(value=>value.trim()).filter(Boolean))].map(name=>({name,role:'party'}));}
function proposalTitle(action){return action.actionType==='draft_email'?'Email draft':action.actionType==='create_document'?'Legal-document draft':action.actionType==='create_social_post'?'Social post draft':'Proposed task';}
function proposalPreview(action){const input=action.input??{};return [input.title??input.subject,input.recipients?.length?`To: ${input.recipients.join(', ')}`:null,input.networks?.length?`Channels: ${input.networks.join(', ')}`:null,input.dueDate?`Due: ${input.dueDate}`:null,input.description??input.body??input.content,input.hashtags?.length?input.hashtags.map(tag=>`#${String(tag).replace(/^#/,'')}`).join(' '):null].filter(Boolean).join('\n\n');}
function observationPreview(observation){const data=observation.data??{};return [data.title??data.description??data.name,data.date?`Date: ${data.date}`:null,data.email?`Email: ${data.email}`:null,data.description&&data.title?data.description:null].filter(Boolean).join('\n\n')||JSON.stringify(data,null,2);}
async function decideAction(action,decision,container){container.querySelectorAll('button').forEach((button)=>button.disabled=true);const status=container.querySelector('.decision');status.textContent=`${decision==='approve'?'Approving':'Rejecting'}…`;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/assistant/actions/${encodeURIComponent(action.id)}/decision`,{method:'POST',body:JSON.stringify({version:action.version,decision})});const proposal=result.proposal??result;status.textContent=proposal.status==='approved'?`Approved — ${result.result?.type??'draft'} created`:'Rejected';container.dataset.status=proposal.status;await loadPilotData();}catch(error){status.textContent=error.message;container.querySelectorAll('button').forEach((button)=>button.disabled=false);}}
function renderAction(action){const container=document.createElement('section');container.className='proposal';container.dataset.status=action.status;container.innerHTML=`<header><strong>${escape(proposalTitle(action))}</strong><span class="pill">${escape(action.status)}</span></header><pre></pre><footer><span class="decision">${action.status==='pending'?'Attorney decision required':escape(action.status)}</span></footer>`;appendCaseLinkedText(container.querySelector('pre'),proposalPreview(action));if(action.status==='pending'){const footer=container.querySelector('footer');const approve=document.createElement('button');approve.className='primary';approve.textContent=action.actionType==='create_task'?'Approve task':'Approve draft';approve.addEventListener('click',()=>decideAction(action,'approve',container));const reject=document.createElement('button');reject.className='danger';reject.textContent='Reject';reject.addEventListener('click',()=>decideAction(action,'reject',container));footer.append(approve,reject);}return container;}
async function decideObservation(observation,decision,container){container.querySelectorAll('button').forEach((button)=>button.disabled=true);const status=container.querySelector('.decision');status.textContent=`${decision==='accept'?'Accepting':'Rejecting'}…`;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/intelligence/observations/${encodeURIComponent(observation.id)}/decision`,{method:'POST',body:JSON.stringify({decision})});status.textContent=result.observation.status==='accepted'?`Accepted into firm knowledge${result.result?.type?` as ${result.result.type}`:''}`:'Rejected';container.dataset.status=result.observation.status;}catch(error){status.textContent=error.message;container.querySelectorAll('button').forEach((button)=>button.disabled=false);}}
function renderObservation(observation){const container=document.createElement('section');container.className='proposal observation';container.dataset.status=observation.status;const confidence=Math.round(Number(observation.confidence??0)*100);container.innerHTML=`<header><strong>${escape(observation.kind.replaceAll('_',' '))}</strong><span class="pill">${confidence}% confidence · ${escape(observation.status)}</span></header><pre></pre><footer><span class="decision">${observation.status==='candidate'?'Verify before adding to firm knowledge':escape(observation.status)}</span></footer>`;appendCaseLinkedText(container.querySelector('pre'),observationPreview(observation));if(observation.status==='candidate'){const footer=container.querySelector('footer');const accept=document.createElement('button');accept.className='primary';accept.textContent='Accept';accept.addEventListener('click',()=>decideObservation(observation,'accept',container));const reject=document.createElement('button');reject.className='danger';reject.textContent='Reject';reject.addEventListener('click',()=>decideObservation(observation,'reject',container));footer.append(accept,reject);}return container;}
function appendSourceLists(message,sources=[],webSources=[]){if(sources.length){const source=document.createElement('div');source.className='sources';const label=item=>{const location=item.sourceLocation?.page?`p. ${item.sourceLocation.page}`:item.sourceLocation?.section?item.sourceLocation.section:null;const review=item.reviewStatus==='candidate'?'unreviewed AI extraction':item.reviewStatus==='accepted'?'attorney accepted':item.reviewStatus==='source_extraction'?'source passage · verify original':null;return [item.title??item.objectId,location,review].filter(Boolean).join(' · ');};appendCaseLinkedText(source,`Atlas records: ${sources.map(label).join(' | ')}`);message.append(source);}if(webSources.length){const web=document.createElement('div');web.className='sources web-sources';web.append(document.createTextNode('Public web sources: '));let links=0;webSources.forEach(item=>{let url;try{url=new URL(item.url);}catch{return;}if(!['http:','https:'].includes(url.protocol))return;if(links)web.append(document.createTextNode(' · '));const link=document.createElement('a');link.href=url.href;link.target='_blank';link.rel='noopener noreferrer';link.textContent=item.title??url.hostname;web.append(link);links+=1;});if(links)message.append(web);}}
function clearVisibleExchange(transcriptId){byId(transcriptId).replaceChildren();}
function appendMessage(role,text,sources=[],actions=[],webSources=[]){const message=document.createElement('article');message.className=`message ${role}`;message.innerHTML=`<header>${role==='atlas'?'Atlas · firm digital twin':'You'}</header><div></div>`;appendCaseLinkedText(message.querySelector('div'),text);appendSourceLists(message,sources,webSources);if(actions.length){const proposals=document.createElement('div');proposals.className='actions';actions.forEach((action)=>proposals.append(renderAction(action)));message.append(proposals);}byId('transcript').append(message);message.scrollIntoView({behavior:'smooth',block:'nearest'});}
function appendWorkspaceMessage(role,text,sources=[],actions=[],webSources=[]){const message=document.createElement('article');message.className=`message ${role}`;message.innerHTML=`<header>${role==='atlas'?'Atlas · unified workspace · firm digital twin':'You'}</header><div></div>`;appendCaseLinkedText(message.querySelector('div'),text);appendSourceLists(message,sources,webSources);if(actions.length){const proposals=document.createElement('div');proposals.className='actions';actions.forEach(action=>proposals.append(renderAction(action)));message.append(proposals);}byId('workspaceAssistantTranscript').append(message);message.scrollIntoView({behavior:'smooth',block:'nearest'});}
function appendTwinMessage(role,text,sources=[],actions=[],webSources=[]){const message=document.createElement('article');message.className=`twin-message ${role}`;message.innerHTML=`<strong>${role==='atlas'?'Atlas':'You'}</strong><div></div>`;appendCaseLinkedText(message.querySelector('div'),text);appendSourceLists(message,sources,webSources);if(actions.length){const proposals=document.createElement('div');proposals.className='actions';actions.forEach(action=>proposals.append(renderAction(action)));message.append(proposals);}byId('twinTranscript').append(message);byId('twinTranscript').scrollTop=byId('twinTranscript').scrollHeight;}
async function submitCommand(prompt){const text=prompt.trim();if(!text)return;const submit=byId('commandSubmit');submit.disabled=true;clearVisibleExchange('transcript');byId('commandStatus').textContent='Atlas is examining authorized firm knowledge, server computations, and permitted public research…';appendMessage('user',text);byId('commandInput').value='';try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/assistant/query`,{method:'POST',body:JSON.stringify({prompt:text,...(conversationId?{conversationId}:{})})});conversationId=result.conversationId;appendMessage('atlas',result.answer,result.sources??[],result.actionProposals??[],result.webSources??[]);byId('commandStatus').textContent=result.actionProposals?.length?'Atlas prepared reviewable work below. Nothing was sent or filed.':result.webSources?.length?'Response grounded in the firm twin and cited public sources.':'Response grounded in the authorized firm twin.';}catch(error){appendMessage('atlas',`I could not complete that request: ${error.message}`);byId('commandStatus').textContent=error.message;}finally{submit.disabled=false;byId('commandInput').focus();}}
async function submitWorkspaceCommand(prompt){const text=prompt.trim();if(!text)return;const submit=byId('workspaceAssistantSubmit');submit.disabled=true;clearVisibleExchange('workspaceAssistantTranscript');byId('workspaceAssistantStatus').textContent='Atlas is examining authorized firm knowledge, legal work, server computations, and permitted public research…';appendWorkspaceMessage('user',text);byId('workspaceAssistantInput').value='';try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/assistant/query`,{method:'POST',body:JSON.stringify({prompt:text,...(conversationId?{conversationId}:{})})});conversationId=result.conversationId;appendWorkspaceMessage('atlas',result.answer,result.sources??[],result.actionProposals??[],result.webSources??[]);byId('workspaceAssistantStatus').textContent=result.actionProposals?.length?'Atlas prepared reviewable work below. Nothing was sent or filed.':result.webSources?.length?'Response grounded in the firm twin and cited public sources.':'Response grounded in the authorized firm twin.';await loadPilotData();}catch(error){appendWorkspaceMessage('atlas',`I could not complete that request: ${error.message}`);byId('workspaceAssistantStatus').textContent=error.message;}finally{submit.disabled=false;byId('workspaceAssistantInput').focus();}}
function normalized(value){return String(value??'').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim();}
function requestedMatter(prompt){const query=normalized(prompt);const matters=pilotObjects.filter(object=>object.dimension==='matter');const exact=matters.filter(matter=>{const caseNumber=normalized(matter.state?.caseNumber);const title=normalized(matter.title);return Boolean((caseNumber&&query.includes(caseNumber))||(title&&query.includes(title)));});if(exact.length===1)return exact[0];const candidates=matters.filter(matter=>normalized(matter.title).split(' ').filter(word=>word.length>3).some(word=>query.includes(word)));return candidates.length===1?candidates[0]:null;}
function isWorkRequest(query){const action=/\b(draft|prepare|create|write|summarize|analyse|analyze|review|research|compare|organize|respond|compose|calculate|prioritize|find|investigate|identify|determine|assess|recommend|evaluate|explain|perform|complete|update)\b/.test(query);const workQuestion=/\b(what|which|how|why|should|could|can)\b/.test(query)&&/\b(next|important|urgent|priority|priorities|task|tasks|deadline|deadlines|risk|risks|work|strategy|motion|email|document)\b/.test(query);return action||workQuestion;}
function routeHomeCommand(prompt){const text=prompt.trim();if(!text)return;const query=normalized(text);if(isWorkRequest(query)){byId('commandInput').value='';showView('workspace');submitWorkspaceCommand(text);return;}const navigation=/\b(open|go to|take me to|navigate to|show|view)\b/.test(query);if(navigation){const matter=requestedMatter(text);if(matter){byId('commandInput').value='';openMatter(matter);return;}for(const [pattern,view] of [[/\b(workspace|my work)\b/,'workspace'],[/\b(event|events|activity|activities|firm timeline)\b/,'events'],[/\b(case|cases|matter|matters)\b/,'matters'],[/\b(email|inbox)\b/,'email'],[/\b(calendar)\b/,'calendar'],[/\b(task|tasks)\b/,'tasks'],[/\b(client|clients|contact|contacts)\b/,'clients'],[/\b(document|documents|file|files)\b/,'documents'],[/\b(social|social media|linkedin|facebook|instagram|posts)\b/,'communications'],[/\b(phone assistant|virtual receptionist|answering service)\b/,'voice'],[/\b(import|migration|migrate|clio|mycase|cms)\b/,'migration'],[/\b(communication|communications|call|calls|text|texts|texting|sms)\b/,'communications'],[/\b(accounting|billing|invoice|invoices|payment|payments|receivables)\b/,'accounting']])if(pattern.test(query)){byId('commandInput').value='';showView(view);return;}}submitCommand(text);}
async function submitTwinCommand(prompt){const text=prompt.trim();if(!text)return;const submit=byId('twinSubmit');submit.disabled=true;clearVisibleExchange('twinTranscript');byId('twinStatus').textContent='Atlas is examining the authorized firm twin and permitted public sources…';appendTwinMessage('user',text);byId('twinInput').value='';try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/assistant/query`,{method:'POST',body:JSON.stringify({prompt:text,...(conversationId?{conversationId}:{})})});conversationId=result.conversationId;appendTwinMessage('atlas',result.answer,result.sources??[],result.actionProposals??[],result.webSources??[]);byId('twinStatus').textContent=result.actionProposals?.length?'Review required; nothing was sent or filed.':result.webSources?.length?'Grounded in firm knowledge and cited public sources.':'Grounded in authorized firm knowledge.';}catch(error){appendTwinMessage('atlas',`I could not complete that request: ${error.message}`);byId('twinStatus').textContent=error.message;}finally{submit.disabled=false;byId('twinInput').focus();}}
async function markReviewed(item,article,button){button.disabled=true;try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/home/while-you-were-gone/${encodeURIComponent(item.id)}`,{method:'PATCH',body:JSON.stringify({status:'reviewed'})});article.remove();workspaceAwareness=workspaceAwareness.filter(entry=>entry.id!==item.id);renderWorkspaceWork();}catch(error){button.disabled=false;byId('feedStatus').textContent=error.message;}}
async function loadFeed(){byId('feedStatus').textContent='Loading verified awareness items…';byId('feed').replaceChildren();try{const items=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/home/while-you-were-gone`);workspaceAwareness=items;renderWorkspaceWork();byId('attentionCount').textContent=String(items.length);byId('feedStatus').textContent=items.length?`${items.length} item${items.length===1?'':'s'} require your attention.`:'No unreviewed events need your attention.';for(const item of items){const article=document.createElement('article');article.className='item';article.dataset.priority=item.priority;const content=document.createElement('div');content.innerHTML=`<span class="pill">${escape(item.priority)} · ${escape(item.category)}</span><h3></h3><p></p><small>${item.observations?.length??0} observations · ${item.actions?.length??0} proposed actions · ${escape(item.reviewStatus)}</small>`;appendCaseLinkedText(content.querySelector('h3'),item.headline);appendCaseLinkedText(content.querySelector('p'),item.summary);if(item.observations?.length){const observations=document.createElement('div');observations.className='actions';item.observations.forEach((observation)=>observations.append(renderObservation(observation)));content.append(observations);}if(item.actions?.length){const actions=document.createElement('div');actions.className='actions';item.actions.forEach((action)=>actions.append(renderAction(action)));content.append(actions);}const reviewed=document.createElement('button');reviewed.textContent='Mark reviewed';reviewed.addEventListener('click',()=>markReviewed(item,article,reviewed));article.append(content,reviewed);byId('feed').append(article);}}catch(error){workspaceAwareness=[];renderWorkspaceWork();byId('attentionCount').textContent='!';byId('feedStatus').textContent=error.message;}}
function renderMatters(matters){byId('matterList').replaceChildren();byId('matterStatus').textContent=matters.length?`${matters.length} active matter${matters.length===1?'':'s'} in this workspace.`:'No matters have been created yet.';if(!matters.length){const empty=document.createElement('div');empty.className='empty';empty.textContent='Your firm’s matters will appear here.';byId('matterList').append(empty);return;}for(const matter of matters){const row=document.createElement('article');row.className='matter-row';const detail=document.createElement('div');detail.innerHTML=`<h3></h3><p>${escape(matter.state?.caseNumber??'No case number')} · ${escape(matter.type)} · Updated ${escape(new Date(matter.updatedAt).toLocaleDateString())}</p>`;detail.querySelector('h3').append(caseLink(matter));const open=document.createElement('button');open.textContent='Open workspace';open.addEventListener('click',()=>openMatter(matter));row.append(detail,open);byId('matterList').append(row);}}
function relatedToMatter(object,matterId){return object.parentObjectId===matterId||object.state?.matterId===matterId;}
function objectCategory(object){if(object.type==='task')return'tasks';if(object.type==='deadline')return'deadlines';if(['invoice','payment','refund','payment_request','financing_application'].includes(object.type))return'billing';if(object.dimension==='client'||object.dimension==='person')return'clients';if(object.dimension==='document')return'documents';if(['email','phone_call','communication'].includes(object.type))return'communications';return'overview';}
function renderMatterTab(tab){document.querySelectorAll('[data-matter-tab]').forEach(button=>button.classList.toggle('active',button.dataset.matterTab===tab));const content=byId('matterContent');content.replaceChildren();if(tab==='timeline'){const timeline=document.createElement('div');timeline.className='timeline';for(const event of matterEvents){const item=document.createElement('article');item.innerHTML=`<strong>${escape(event.type.replaceAll('.',' '))}</strong><div class="muted">${escape(new Date(event.occurredAt).toLocaleString())} · ${escape(event.source)}</div>`;timeline.append(item);}if(!matterEvents.length)timeline.innerHTML='<div class="empty">No timeline events yet.</div>';content.append(timeline);return;}const children=pilotObjects.filter(object=>object.dimension!=='evidence'&&relatedToMatter(object,activeMatter.id)&&(tab==='overview'||objectCategory(object)===tab));if(tab==='overview'){const summary=document.createElement('div');summary.className='grid';summary.innerHTML=`<div class="object-card"><span class="pill">Client</span><h3>${escape(activeMatter.state?.clientName??'Not assigned')}</h3></div><div class="object-card"><span class="pill">Connected work</span><h3>${children.length} items</h3></div>`;content.append(summary);}const grid=document.createElement('div');grid.className='object-grid';for(const object of children){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(objectCategory(object))}</span><h3>${escape(object.title)}</h3><p class="muted">${escape(object.type)}${object.state?.date?` · ${escape(new Date(object.state.date).toLocaleDateString())}`:''}</p>`;grid.append(card);}if(tab!=='overview'&&!children.length)grid.innerHTML=`<div class="empty">No ${escape(tab)} connected to this case yet.</div>`;content.append(grid);}
async function openMatter(matter){activeMatter=matter;showView('matter');byId('matterKind').textContent=matter.type;byId('matterName').replaceChildren(caseLink(matter));byId('matterMeta').textContent=[matter.state?.caseNumber,matter.state?.clientName].filter(Boolean).join(' · ')||'Canonical matter workspace';const [health,events]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/matters/${encodeURIComponent(matter.id)}/health`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/events?parentObjectId=${encodeURIComponent(matter.id)}`)]);byId('matterHealth').textContent=`${health.score}%`;matterEvents=events;renderMatterTab('overview');}
function collectionItems(name){const config=collectionConfigs[name];return pilotObjects.filter(object=>name==='communications'?object.dimension==='operation'&&['communication','email','phone_call','voice_call_session','sms_message'].includes(object.type):name==='documents'?object.dimension==='document':object.dimension===config.dimension&&object.type===config.type);}
function matterTitleFor(object){const matter=pilotObjects.find(item=>item.id===(object.parentObjectId??object.state?.matterId));return matter?.title??(object.state?.scope==='firm'?'Firm-wide':'Scope pending');}
function workspaceCategory(object){if(object.dimension==='matter')return'cases';if(object.state?.draft||object.type.includes('draft'))return'drafts';if(object.type==='task')return'tasks';if(object.type==='deadline')return'deadlines';if(['invoice','payment','refund','payment_request','financing_application','bank_transaction'].includes(object.type))return'accounting';if(object.dimension==='client'||object.dimension==='person')return'clients';if(object.dimension==='document')return'documents';if(['incoming_email','email'].includes(object.type))return'email';if(['phone_call','communication'].includes(object.type))return'communications';return'other';}
function workspaceMatter(matterId){return pilotObjects.find(object=>object.dimension==='matter'&&object.id===matterId)??null;}
function workspaceEntries(){const objects=pilotObjects.filter(object=>object.dimension!=='evidence'&&!['completed','closed'].includes(object.state?.status)).map(object=>({id:object.id,kind:'object',category:workspaceCategory(object),title:object.title,detail:(object.dimension==='matter'?[object.type,object.state?.caseNumber]:[object.type,matterTitleFor(object)]).filter(Boolean).join(' · '),timestamp:object.updatedAt??object.createdAt,search:JSON.stringify(object),matter:object.dimension==='matter'?object:workspaceMatter(object.parentObjectId??object.state?.matterId),raw:object}));const actions=workspaceActions.filter(action=>action.status==='pending').map(action=>({id:action.id,kind:'action',category:action.actionType==='create_task'?'tasks':'drafts',title:proposalTitle(action),detail:'Awaiting attorney approval',timestamp:action.createdAt,search:JSON.stringify(action),matter:workspaceMatter(action.input?.matterId),raw:action}));const awareness=workspaceAwareness.filter(item=>item.reviewStatus!=='reviewed').map(item=>({id:item.id,kind:'awareness',category:'review',title:item.headline,detail:item.summary,timestamp:item.createdAt,search:JSON.stringify(item),matter:workspaceMatter(item.matterId??item.objectId),raw:item}));return [...objects,...actions,...awareness].sort((a,b)=>String(b.timestamp??'').localeCompare(String(a.timestamp??'')));}
function renderWorkspaceWork(){const list=byId('workspaceWorkList');if(!list)return;const category=byId('workspaceFilter').value;const query=normalized(byId('workspaceSearch').value);const items=workspaceEntries().filter(item=>(category==='all'||item.category===category)&&(!query||normalized(`${item.title} ${item.detail} ${item.search}`).includes(query)));byId('workspaceItemCount').textContent=`${items.length} item${items.length===1?'':'s'}`;list.replaceChildren();for(const item of items){const card=document.createElement('article');card.className='object-card';if(item.kind==='action'){card.append(casePill(item.category,item.matter,'Firm work'),renderAction(item.raw));}else{card.append(casePill(item.category,item.matter,''));const heading=document.createElement('h3');appendCaseLinkedText(heading,item.title);const detail=document.createElement('p');detail.className='muted';appendCaseLinkedText(detail,item.detail);card.append(heading,detail);if(item.kind==='awareness'){const review=document.createElement('button');review.textContent='Open review inbox';review.addEventListener('click',()=>{showView('dashboard');byId('reviewInbox').scrollIntoView({behavior:'smooth',block:'start'});});card.append(review);}else if(item.matter){const open=document.createElement('button');open.textContent='Open case';open.addEventListener('click',()=>openMatter(item.matter));card.append(open);}}list.append(card);}if(!items.length)list.innerHTML='<div class="empty">No work matches these filters.</div>';}
function homeWorkDate(item){return item.state?.date??item.state?.dueDate??item.input?.dueDate??null;}
function homeWorkItems(){const canonical=pilotObjects.filter(item=>['task','deadline'].includes(item.type)&&!['completed','closed'].includes(item.state?.status)).map(item=>({kind:item.type,title:item.title,date:homeWorkDate(item),matter:workspaceMatter(item.parentObjectId??item.state?.matterId),raw:item}));const suggested=workspaceActions.filter(action=>action.status==='pending'&&action.actionType==='create_task').map(action=>({kind:'suggested',title:action.input?.title??'Atlas suggested task',date:homeWorkDate(action),matter:workspaceMatter(action.input?.matterId),raw:action}));return [...suggested,...canonical].sort((a,b)=>String(a.date??'9999').localeCompare(String(b.date??'9999'))||a.title.localeCompare(b.title));}
function appendWorkQueueItem(list,item){const card=document.createElement('article');card.className='object-card home-work-item';if(item.kind==='suggested'){card.append(casePill('Atlas suggested task',item.matter,''),renderAction(item.raw));}else{const due=item.date?new Date(item.date):null;const validDue=due&&!Number.isNaN(due.getTime());card.append(casePill(item.kind==='deadline'?'Case deadline':'Open task',item.matter,''));const heading=document.createElement('h3');appendCaseLinkedText(heading,item.title);const detail=document.createElement('p');detail.className='muted';detail.textContent=validDue?`Due ${due.toLocaleString()}`:'No due date assigned';card.append(heading,detail);const open=document.createElement('button');open.textContent=item.matter?'Open case':'View tasks';open.addEventListener('click',()=>item.matter?openMatter(item.matter):showView('tasks'));card.append(open);}list.append(card);}
function renderHomeWorkQueue(){const list=byId('homeWorkList');if(!list)return;const items=homeWorkItems();byId('homeWorkStatus').textContent=items.length?`${items.length} open task${items.length===1?' or deadline':'s and deadlines'} across the firm.`:'No open tasks, deadlines, or Atlas suggestions.';list.replaceChildren();items.forEach(item=>appendWorkQueueItem(list,item));if(!items.length)list.innerHTML='<div class="empty">Atlas has no open work to show.</div>';}
function renderCollection(name){activeCollection=name;const config=collectionConfigs[name];byId('collectionTitle').textContent=config.title;byId('collectionNameLabel').textContent=config.label;byId('newCollectionItem').textContent=name==='documents'?'Upload document':`Add ${config.label.toLowerCase()}`;byId('newCollectionItem').classList.toggle('hidden',Boolean(config.readOnly));byId('collectionForm').classList.add('hidden');byId('collectionFileLabel').classList.toggle('hidden',name!=='documents');byId('collectionFile').required=name==='documents';byId('collectionName').required=name!=='documents';const connectedView=['email','calendar'].includes(name);byId('emailConnection').classList.toggle('hidden',!connectedView);if(connectedView)void loadEmailConnections();const textingView=name==='communications';byId('smsConnection').classList.toggle('hidden',!textingView);if(textingView)void loadSmsAssistant();const matterSelect=byId('collectionMatter');matterSelect.replaceChildren();const prompt=document.createElement('option');prompt.value='';prompt.textContent='Select the required case';prompt.disabled=true;prompt.selected=true;matterSelect.append(prompt);for(const matter of pilotObjects.filter(item=>item.dimension==='matter')){const option=document.createElement('option');option.value=matter.id;option.textContent=matter.title;matterSelect.append(option);}byId('collectionDateLabel').classList.toggle('hidden',!['communications','tasks','deadlines'].includes(name));const list=byId('collectionList');list.replaceChildren();if(name==='tasks'){const items=homeWorkItems();byId('collectionStatus').textContent=`${items.length} open canonical task, case deadline, or pending Atlas task suggestion${items.length===1?'':'s'} for this firm.`;items.forEach(item=>appendWorkQueueItem(list,item));if(!items.length)list.innerHTML='<div class="empty">No open tasks, deadlines, or Atlas suggestions.</div>';return;}const items=collectionItems(name);byId('collectionStatus').textContent=config.readOnly?`${items.length} canonical ${config.title.toLowerCase()} item(s) available to this firm.`:`${items.length} ${config.title.toLowerCase()} owned exclusively by this firm and scoped to cases.`;for(const item of items){const card=document.createElement('article');card.className='object-card';const matter=workspaceMatter(item.parentObjectId??item.state?.matterId);const when=item.state?.receivedAt??item.state?.sentAt??item.state?.date;const detail=item.type==='sms_message'?`${item.state?.direction==='outgoing'?'To':'From'}: ${item.state?.direction==='outgoing'?item.state?.to:item.state?.from} · ${item.state?.body??''}`:item.state?.from??item.state?.details??item.type;card.append(casePill('',matter,matterTitleFor(item)));const heading=document.createElement('h3');appendCaseLinkedText(heading,item.title);const description=document.createElement('p');description.className='muted';appendCaseLinkedText(description,`${detail}${when?` · ${new Date(when).toLocaleString()}`:''}`);card.append(heading,description);if(name==='documents'&&String(item.state?.storageRef??'').startsWith('atlas-blob://')){const download=document.createElement('button');download.type='button';download.textContent='Download verified file';download.addEventListener('click',()=>void downloadDocument(item,download));card.append(download);}list.append(card);}if(!items.length)list.innerHTML=`<div class="empty">No ${escape(config.title.toLowerCase())} has been synchronized for this firm.</div>`;}
async function loadPilotData(){const [workspace,subscription,objects,actions]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/subscription`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/assistant/actions`)]);pilotObjects=objects;workspaceActions=actions;byId('firmName').textContent=workspace.name;byId('firmRole').textContent=`${subscription.plan} · ${subscription.status} · ${subscription.seatLimit} seats`;const matters=objects.filter((item)=>item.dimension==='matter');const tasks=objects.filter((item)=>item.dimension==='operation'&&item.type==='task'&&item.state?.status!=='completed');const deadlines=objects.filter((item)=>item.type==='deadline'&&item.state?.status!=='completed');byId('matterCount').textContent=String(matters.length);byId('taskCount').textContent=String(tasks.length);byId('deadlineCount').textContent=String(deadlines.length);renderMatters(matters);renderWorkspaceWork();renderHomeWorkQueue();await Promise.all([loadFeed(),loadFirmEvents(),loadConflictAlerts()]);}
function showView(name){activeView=name;const collection=Boolean(collectionConfigs[name]);document.querySelectorAll('.nav button').forEach((button)=>button.classList.toggle('active',button.dataset.view===name));byId('view-dashboard').classList.toggle('hidden',name!=='dashboard');byId('view-workspace').classList.toggle('hidden',name!=='workspace');byId('view-events').classList.toggle('hidden',name!=='events');byId('view-matters').classList.toggle('hidden',name!=='matters');byId('view-matter').classList.toggle('hidden',name!=='matter');byId('view-collection').classList.toggle('hidden',!collection);byId('view-social').classList.toggle('hidden',name!=='communications');byId('view-migration').classList.toggle('hidden',name!=='migration');byId('view-voice').classList.toggle('hidden',name!=='voice');byId('view-accounting').classList.toggle('hidden',name!=='accounting');byId('view-settings').classList.toggle('hidden',name!=='settings');byId('twinDock').classList.toggle('hidden',!shouldShowTwinDock(name));const placeholder=!['dashboard','workspace','events','matters','matter','migration','voice','accounting','settings'].includes(name)&&!collection;byId('view-placeholder').classList.toggle('hidden',!placeholder);const title=name==='dashboard'?'Home':name==='workspace'?'Workspace':name==='matters'?'Cases':name==='matter'?(activeMatter?.title??'Case'):name==='voice'?'Phone Assistant':name[0].toUpperCase()+name.slice(1);byId('viewTitle').replaceChildren(name==='matter'&&activeMatter?caseLink(activeMatter):document.createTextNode(title));if(name==='workspace')renderWorkspaceWork();if(name==='events')renderFirmEvents();if(name==='communications')void loadSocial();if(name==='migration')void loadMigration();if(name==='voice')void loadVoiceAssistant();if(name==='accounting')void loadAccounting();if(name==='settings'){void loadSettings();void loadSecuritySettings();}if(collection)renderCollection(name);if(placeholder)byId('placeholderTitle').textContent=`${title} workspace`;}
function money(minor,currency='USD'){return new Intl.NumberFormat(undefined,{style:'currency',currency}).format(Number(minor??0)/100);}
function replaceOptions(select,items,placeholder,valueFor,labelFor){select.replaceChildren();const first=document.createElement('option');first.value='';first.textContent=placeholder;first.disabled=true;first.selected=true;select.append(first);for(const item of items){const option=document.createElement('option');option.value=valueFor(item);option.textContent=labelFor(item);select.append(option);}}
function renderAccountingProviders(){const all=accountingProviders??{payments:[],banks:[],financing:[]};const connections=byId('accountingProviderList');connections.replaceChildren();for(const provider of [...all.payments.map(item=>({...item,kind:'Payment processor'})),...all.banks.map(item=>({...item,kind:'Bank data connection'}))]){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(provider.kind)}</span><h3>${escape(provider.name)}</h3><p class="muted">${escape(provider.hostedCheckout?'Hosted, tokenized payment collection':'Secure provider authorization')}</p>`;connections.append(card);}if(!connections.children.length)connections.innerHTML='<div class="empty">No production bank or payment provider is configured yet. Atlas will never ask for bank or card credentials directly.</div>';const finance=byId('financeProviderList');finance.replaceChildren();for(const provider of all.financing){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">External lender</span><h3>${escape(provider.name)}</h3><p class="muted">Client-consented application handoff; Atlas does not underwrite or lend.</p>`;finance.append(card);}if(!finance.children.length)finance.innerHTML='<div class="empty">No legal-fee financing partner is configured. Candidate providers are being evaluated for consented application handoff and status integration.</div>';}
function renderCryptoAccounting(){const providers=accountingProviders?.crypto??[];const accounts=pilotObjects.filter(item=>item.type==='crypto_receiving_account'&&item.state?.status==='active');const requests=pilotObjects.filter(item=>item.type==='crypto_payment_request');const providerSelect=byId('cryptoProvider');providerSelect.replaceChildren();const providerPrompt=document.createElement('option');providerPrompt.value='';providerPrompt.disabled=true;providerPrompt.selected=true;providerPrompt.textContent=providers.length?'Select configured network':'No crypto provider configured';providerSelect.append(providerPrompt);for(const provider of providers){const option=document.createElement('option');option.value=provider.name;option.textContent=`${provider.asset} · ${provider.network}`;providerSelect.append(option);}providerSelect.disabled=!providers.length;byId('cryptoAddress').disabled=!providers.length;byId('cryptoAccountForm').querySelector('button').disabled=!providers.length;replaceOptions(byId('cryptoReceivingAccount'),accounts,'Select receiving address',item=>item.id,item=>`${item.state.asset} · ${item.state.network} · ${item.state.address}`);replaceOptions(byId('cryptoInvoice'),(accountingSummary?.invoices??[]).filter(row=>row.outstandingMinor>0),'Select an unpaid invoice',row=>row.invoice.id,row=>`${row.invoice.title} · ${money(row.outstandingMinor,row.invoice.state.currency)} due`);byId('cryptoReceivingAccount').disabled=!accounts.length;byId('cryptoRequestForm').querySelector('button').disabled=!accounts.length;byId('cryptoServiceStatus').textContent=providers.length?'Provider connected':'Setup required';const accountList=byId('cryptoAccountList');accountList.replaceChildren();for(const account of accounts){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(account.state.asset)} · ${escape(account.state.network)}</span><h3>${escape(account.title)}</h3><p class="muted">${escape(account.state.address)}</p><small>Firm-controlled wallet · Atlas custody: no</small>`;accountList.append(card);}if(!accounts.length)accountList.innerHTML='<div class="empty">No receiving address is connected. Configure an approved blockchain provider in the Atlas deployment, then add the firm’s public wallet address.</div>';const requestList=byId('cryptoRequestList');requestList.replaceChildren();for(const paymentRequest of requests){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(paymentRequest.state.status)} · ${escape(paymentRequest.state.asset)}</span><h3>${escape(paymentRequest.title)}</h3><p>${escape(money(paymentRequest.state.amountMinor,paymentRequest.state.currency))} · ${escape(paymentRequest.state.network)}</p><p class="muted">Pay to ${escape(paymentRequest.state.destinationAddress)}</p><form><label>Blockchain transaction hash<input required autocomplete="off" placeholder="0x…"></label><button class="primary" type="submit">Verify and record payment</button></form><small class="decision"></small>`;card.querySelector('form').addEventListener('submit',async(event)=>{event.preventDefault();const status=card.querySelector('.decision');status.textContent='Checking blockchain confirmations…';try{const confirmed=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/accounting/crypto/confirmations`,{method:'POST',body:JSON.stringify({paymentRequestId:paymentRequest.id,transactionHash:card.querySelector('input').value})});status.textContent=confirmed.status==='confirmed'?'Confirmed and recorded in accounting.':`Pending · ${confirmed.confirmations}/${confirmed.requiredConfirmations} confirmations`;await loadPilotData();await loadAccounting();}catch(error){status.textContent=error.message;}});requestList.append(card);}if(!requests.length)requestList.innerHTML='<div class="empty">No crypto payment request has been created.</div>';}
function renderQuickBooksAccounting(){const provider=accountingCmsProviders.find(item=>item.name==='quickbooks');const connection=accountingCmsConnections.find(item=>item.provider==='quickbooks'&&item.status!=='disconnected');const summary=accountingSummary?.quickBooks??{recordCount:0,receivableMinor:0,paymentsMinor:0,expensesMinor:0,entries:[]};byId('quickBooksStatus').textContent=connection?(connection.status==='connected'?'Connected':'Attention required'):(provider?'Ready to connect':'Setup required');byId('quickBooksConnect').hidden=Boolean(connection);byId('quickBooksConnect').disabled=!provider;byId('quickBooksSync').hidden=!connection;byId('quickBooksDisconnect').hidden=!connection;byId('quickBooksSync').disabled=connection?.status==='error';byId('quickBooksRecords').textContent=String(summary.recordCount);byId('quickBooksReceivable').textContent=money(summary.receivableMinor);byId('quickBooksPayments').textContent=money(summary.paymentsMinor);byId('quickBooksExpenses').textContent=money(summary.expensesMinor);byId('quickBooksLastSync').textContent=connection?.lastSyncedAt?`Last sync ${new Date(connection.lastSyncedAt).toLocaleString()}`:'Not synchronized';const message=byId('quickBooksMessage');message.textContent=provider?(connection?'QuickBooks finances are mirrored read-only. Imported records retain QuickBooks provenance and become available to Atlas intelligence.':'Connect the firm’s QuickBooks company to populate accounts, customers, vendors, invoices, payments, expenses, bills, deposits, credits, and journals.'):'An administrator must configure the Intuit application credentials before this firm can connect QuickBooks.';const list=byId('quickBooksEntryList');list.replaceChildren();for(const entry of summary.entries??[]){const card=document.createElement('article');card.className='object-card';const amount=entry.state.amountMinor??entry.state.balanceMinor;card.innerHTML=`<span class="pill">${escape(String(entry.state.entryType??'record').replaceAll('_',' '))}</span><h3>${escape(entry.title)}</h3><p>${amount===null||amount===undefined?'':escape(money(amount,entry.state.currency))}</p><small>${escape(entry.state.txnDate??entry.state.dueDate??'QuickBooks financial record')} · Read-only source</small>`;list.append(card);}if(!list.children.length)list.innerHTML='<div class="empty">No QuickBooks finances have been imported yet.</div>';}
function renderAccounting(){const summary=accountingSummary;if(!summary)return;byId('accountingBilled').textContent=money(summary.billedMinor,summary.currency);byId('accountingPaid').textContent=money(summary.paidMinor,summary.currency);byId('accountingReceivable').textContent=money(summary.receivableMinor,summary.currency);byId('accountingTrust').textContent=money(summary.trustReceivedMinor,summary.currency);byId('invoiceCount').textContent=`${summary.invoiceCount} invoice${summary.invoiceCount===1?'':'s'}`;const list=byId('invoiceList');list.replaceChildren();for(const row of summary.invoices){const invoice=row.invoice;const matter=workspaceMatter(invoice.parentObjectId??invoice.state?.matterId);const card=document.createElement('article');card.className='object-card';card.append(casePill(invoice.state.status,matter,matterTitleFor(invoice)));const heading=document.createElement('h3');appendCaseLinkedText(heading,invoice.title);const balance=document.createElement('p');balance.textContent=`${money(row.amountMinor,invoice.state.currency)} billed · ${money(row.outstandingMinor,invoice.state.currency)} outstanding`;const detail=document.createElement('small');detail.textContent=`${invoice.state.trustTreatment==='trust'?'Trust deposit':'Operating funds'}${invoice.state.dueAt?` · Due ${new Date(invoice.state.dueAt).toLocaleDateString()}`:''}`;card.append(heading,balance,detail);list.append(card);}if(!summary.invoices.length)list.innerHTML='<div class="empty">No invoices yet. Create the first case-owned invoice above.</div>';const matters=pilotObjects.filter(item=>item.dimension==='matter');replaceOptions(byId('invoiceMatter'),matters,'Select a case',item=>item.id,item=>item.title);replaceOptions(byId('paymentInvoice'),summary.invoices.filter(row=>row.outstandingMinor>0),'Select an unpaid invoice',row=>row.invoice.id,row=>`${row.invoice.title} · ${money(row.outstandingMinor,row.invoice.state.currency)} due`);renderAccountingProviders();renderCryptoAccounting();renderQuickBooksAccounting();byId('accountingStatus').textContent='Accounting entries are canonical firm knowledge. Atlas can reason over balances and events, but payments and lending remain with regulated external providers.';}
function renderHostedCheckout(){const providers=(accountingProviders?.payments??[]).filter(item=>item.hostedCheckout&&item.rails?.some(rail=>['ach','card'].includes(rail)));const unpaid=(accountingSummary?.invoices??[]).filter(row=>row.outstandingMinor>0);replaceOptions(byId('checkoutInvoice'),unpaid,'Select an unpaid invoice',row=>row.invoice.id,row=>`${row.invoice.title} · ${money(row.outstandingMinor,row.invoice.state.currency)} due`);replaceOptions(byId('checkoutProvider'),providers,providers.length?'Select processor':'No payment processor configured',item=>item.name,item=>item.name);byId('checkoutStatus').textContent=providers.length?'Processor connected':'Setup required';byId('checkoutForm').querySelector('button').disabled=!providers.length||!unpaid.length;}
async function loadAccounting(){byId('accountingStatus').textContent='Loading canonical accounting…';try{[accountingSummary,accountingProviders,accountingCmsProviders,accountingCmsConnections]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/accounting/summary`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/accounting/providers`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/providers`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections`)]);renderAccounting();renderHostedCheckout();}catch(error){byId('accountingStatus').textContent=error.message;}}
function renderVoiceAssistant(){const state=voiceAssistantState??{configured:false,calls:[]};const config=state.configuration?.state;byId('voiceConnectionStatus').textContent=state.configured?'Configured':'Not configured';if(config){byId('voiceGreeting').value=config.greeting??'';byId('voiceTransferNumber').value=config.transferNumber??'';byId('voiceRecordingEnabled').checked=config.recordingEnabled===true;}byId('voiceCallCount').textContent=`${state.calls.length} recent`;const list=byId('voiceCallList');list.replaceChildren();for(const call of state.calls){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(call.state.status)} · ${escape(call.state.provider)}</span><h3>${escape(call.title)}</h3><p class="muted">${escape(call.state.knownCallerTitle??'Unverified caller')} · ${(call.state.createdWorkIds??[]).length} review item(s) created</p><small>${escape(new Date(call.state.startedAt).toLocaleString())}</small>`;list.append(card);}if(!state.calls.length)list.innerHTML='<div class="empty">No calls have been handled by the phone assistant.</div>';}
async function loadVoiceAssistant(){byId('voiceConnectionStatus').textContent='Loading';try{voiceAssistantState=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/voice-assistant`);renderVoiceAssistant();}catch(error){byId('voiceConnectionStatus').textContent='Unavailable';byId('voiceConfigurationError').textContent=error.message;}}
function showVoiceSimulation(result){const output=byId('voiceSimulatorResult');output.classList.remove('hidden');output.innerHTML=`<strong>Atlas phone assistant</strong><p>${escape(result.prompt)}</p>${result.work?`<small>Created for firm review: ${escape(result.work.title)}</small>`:''}`;byId('voiceSimulatorPrompt').textContent=result.action==='transfer'?'The assistant would transfer this call to the approved firm number.':result.action==='hangup'?'The assistant safely ended the call.':'The assistant is listening for the next response.';}
function providerDisplayName(name){return name==='clio'?'Clio':name==='mycase'?'MyCase':name==='google'?'Google Workspace':name==='microsoft'?'Microsoft 365':name;}
function renderMigration(){const available=new Set(migrationProviders.map(item=>item.name));const connected=new Map(migrationConnections.filter(item=>item.status!=='disconnected'&&!['google','microsoft'].includes(item.provider)).map(item=>[item.provider,item]));const providers=byId('migrationProviderList');providers.replaceChildren();for(const name of ['clio','mycase']){const card=document.createElement('article');card.className='object-card';const connection=connected.get(name);card.innerHTML=`<span class="pill">${connection?'Connected':available.has(name)?'Available':'Setup required'}</span><h3>${escape(providerDisplayName(name))}</h3><p class="muted">${connection?'Read-only coexistence is active. Atlas preserves source provenance.':available.has(name)?'Connect through the provider’s secure authorization screen.':'Add this provider’s approved API credentials to the Atlas deployment before connecting.'}</p>`;const button=document.createElement('button');button.type='button';button.textContent=connection?'Sync now':available.has(name)?`Connect ${providerDisplayName(name)}`:'Not configured';button.disabled=!connection&&!available.has(name);button.addEventListener('click',()=>connection?syncMigrationConnection(connection,button):connectMigrationProvider(name,button));card.append(button);providers.append(card);}const connections=byId('migrationConnectionList');connections.replaceChildren();for(const connection of migrationConnections.filter(item=>!['google','microsoft'].includes(item.provider))){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(connection.status)}</span><h3>${escape(providerDisplayName(connection.provider))} connection</h3><p class="muted">${connection.lastSyncedAt?`Last synchronized ${escape(new Date(connection.lastSyncedAt).toLocaleString())}`:'Awaiting first synchronization'}</p>`;connections.append(card);}byId('migrationConnectionStatus').textContent=connected.size?`${connected.size} connected`:'No CMS connected';const batches=byId('migrationBatchList');batches.replaceChildren();byId('migrationBatchCount').textContent=`${migrationBatches.length} batch${migrationBatches.length===1?'':'es'}`;for(const batch of migrationBatches){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(batch.state.status)} · ${escape(batch.state.provider)}</span><h3>${escape(batch.title)}</h3><p>${Number(batch.state.created??0)} created · ${Number(batch.state.skipped??0)} already imported · ${(batch.state.errors??[]).length} errors</p><small>${escape(new Date(batch.createdAt).toLocaleString())}</small>`;batches.append(card);}if(!migrationBatches.length)batches.innerHTML='<div class="empty">No uploaded migration has been run for this firm.</div>';}
async function loadMigration(){byId('migrationConnectionStatus').textContent='Loading';try{[migrationProviders,migrationConnections,migrationBatches]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/providers`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/migration/imports`)]);renderMigration();}catch(error){byId('migrationConnectionStatus').textContent='Unavailable';byId('migrationConnectionMessage').textContent=error.message;}}
async function connectMigrationProvider(provider,button){button.disabled=true;byId('migrationConnectionMessage').textContent=`Opening ${providerDisplayName(provider)} secure authorization…`;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/${encodeURIComponent(provider)}/authorize`,{method:'POST',body:JSON.stringify({redirectUri:`${window.location.origin}/v1/cms/oauth/callback`})});const authorizationUrl=new URL(result.authorizationUrl);if(authorizationUrl.protocol!=='https:')throw new Error('The provider returned an insecure authorization URL.');const popup=window.open(authorizationUrl.href,'atlas-cms-authorization','popup,width=720,height=820,noopener,noreferrer');if(!popup)throw new Error('Allow the Atlas authorization popup, then try again.');byId('migrationConnectionMessage').textContent=`Complete consent with ${providerDisplayName(provider)}, then return to Atlas.`;}catch(error){byId('migrationConnectionMessage').textContent=error.message;}finally{button.disabled=false;}}
async function syncMigrationConnection(connection,button){button.disabled=true;byId('migrationConnectionMessage').textContent=`Synchronizing ${providerDisplayName(connection.provider)} read-only data…`;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections/${encodeURIComponent(connection.id)}/sync`,{method:'POST'});byId('migrationConnectionMessage').textContent=`Sync complete: ${result.imported} imported, ${result.updated} updated, ${result.tombstones??0} source archives preserved.`;await loadPilotData();await loadMigration();}catch(error){byId('migrationConnectionMessage').textContent=error.message;}finally{button.disabled=false;}}
function renderMigrationPreview(preview){const output=byId('migrationPreview');output.classList.remove('hidden');output.replaceChildren();const heading=document.createElement('strong');heading.textContent=`${preview.totalRecords} records detected · ${preview.canImport?'Ready to import':'Review required'}`;output.append(heading);for(const dataset of preview.datasets){const row=document.createElement('p');row.textContent=`${dataset.file}: ${dataset.count} ${dataset.kind} record${dataset.count===1?'':'s'}`;output.append(row);}for(const issue of preview.issues){const row=document.createElement('p');row.className=issue.severity==='error'?'error':'muted';row.textContent=`${issue.file}: ${issue.message}`;output.append(row);}byId('runMigrationImport').disabled=!preview.canImport||preview.totalRecords===0;}
async function selectedMigrationPayload(){const files=[...byId('migrationFiles').files];if(!files.length)throw new Error('Select at least one CSV or JSON export file.');const total=files.reduce((sum,file)=>sum+file.size,0);if(total>18_000_000)throw new Error('This preview is larger than 18 MB. Split the export into smaller batches.');return {provider:byId('migrationProvider').value,files:await Promise.all(files.map(async file=>({name:file.name,content:await file.text()})))};}
async function enterWorkspace(){document.body.classList.add('atlas-authenticated');byId('password').value='';byId('newOwnerPassword').value='';byId('workspaceSearch').value='';byId('workspaceFilter').value='all';byId('login').classList.add('hidden');byId('onboarding').classList.add('hidden');byId('home').classList.remove('hidden');showView('dashboard');persistSession();try{await loadPilotData();}catch(error){if(!error.message.includes('[FIRM_MFA_REQUIRED]'))throw error;showView('settings');byId('mfaMessage').textContent='This firm requires MFA. Complete account protection before opening firm work.';}}
byId('loginForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('loginError').textContent='';const base=byId('apiBase').value.replace(/\/$/,'');try{session={base,workspaceId:null,token:null,refreshToken:null};const mfaCode=byId('loginMfaCode').value.trim();const result=await request('/v1/auth/login',{method:'POST',body:JSON.stringify({email:byId('email').value,password:byId('password').value,...(mfaCode?{mfaCode}:{})})});session.token=result.accessToken;session.refreshToken=result.refreshToken;const firms=await request('/v1/me/workspaces');if(!firms.length)throw new Error('Your account is not connected to a firm workspace.');session.workspaceId=firms[0].workspace.id;byId('workspaceId').value=session.workspaceId;await enterWorkspace();}catch(error){session=null;clearStoredSession();byId('loginError').textContent=error.message;if(error.message.includes('authenticator or recovery code'))byId('loginMfaCode').focus();}});
async function seedDemoCase(){const caseFile=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`,{method:'POST',body:JSON.stringify({dimension:'matter',type:'civil',title:'Morgan v. Lakeside Property Group',state:{caseNumber:'DEMO-2026-CV-101',clientName:'Taylor Morgan',parties:[{name:'Taylor Morgan',role:'client'},{name:'Lakeside Property Group',role:'opposing party'}],status:'open',ownerName:'Demo Attorney'}})});const common={parentObjectId:caseFile.id,state:{scope:'matter',matterId:caseFile.id,status:'open'}};for(const item of [{dimension:'client',type:'client',title:'Taylor Morgan',state:{email:'taylor.morgan@example.test',phone:'(555) 010-2026'}},{dimension:'document',type:'document',title:'Initial Complaint',state:{documentType:'complaint',draft:false}},{dimension:'operation',type:'communication',title:'Client intake call',state:{occurredAt:new Date().toISOString(),summary:'Fictional intake call for the Atlas product demo.'}},{dimension:'operation',type:'task',title:'Review discovery plan',state:{date:new Date(Date.now()+2*86_400_000).toISOString(),assignedTo:'Demo Attorney'}},{dimension:'operation',type:'deadline',title:'Discovery responses due',state:{date:new Date(Date.now()+5*86_400_000).toISOString(),deadlineType:'discovery',assignedTo:'Demo Attorney'}}])await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`,{method:'POST',body:JSON.stringify({...common,...item,state:{...common.state,...item.state}})});return caseFile;}
async function createDemoFirm(){const button=byId('showOnboarding');button.disabled=true;byId('loginError').textContent='Creating a fictional Atlas demo firm and case…';try{session={base:byId('apiBase').value.replace(/\/$/,''),workspaceId:null,token:null,refreshToken:null};const suffix=`${Date.now()}-${Math.random().toString(16).slice(2)}`;const result=await request('/v1/auth/register-firm',{method:'POST',body:JSON.stringify({firmName:'Atlas Demo Law',name:'Demo Attorney',email:`demo-${suffix}@atlas.local`,password:'fictional-demo-password-only'})});session.workspaceId=result.workspace.id;session.token=result.accessToken;session.refreshToken=result.refreshToken;byId('workspaceId').value=result.workspace.id;await seedDemoCase();byId('loginError').textContent='';await enterWorkspace();}catch(error){session=null;clearStoredSession();byId('loginError').textContent=error.message;}finally{button.disabled=false;}}
