function renderSmsAssistant(){const state=smsState??{configured:false,providerConfigured:false,configuration:null,drafts:[]};byId('smsConnectionStatus').textContent=state.providerConfigured?'Live provider ready':state.configured?'Local review mode':'Not configured';const configuration=state.configuration?.state;if(configuration){byId('smsAutoAcknowledgement').checked=configuration.autoAcknowledgement!==false;byId('smsAcknowledgement').value=configuration.acknowledgement??'';}const list=byId('smsDraftList');list.replaceChildren();for(const draft of state.drafts??[]){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">Human approval required</span><h3>${escape(draft.title)}</h3><label>Recipient<input value="${escape(draft.state?.to)}" readonly></label><label>Review and edit<textarea maxlength="1600">${escape(draft.state?.body)}</textarea></label>`;const send=document.createElement('button');send.className='primary';send.type='button';send.textContent=state.providerConfigured?'Approve and send text':'Provider required to send';send.disabled=!state.providerConfigured;send.addEventListener('click',()=>approveAndSendSmsDraft(draft,card,send));card.append(send);list.append(card);}if(!list.children.length)list.innerHTML='<div class="empty">No text drafts are awaiting review.</div>';byId('smsStatusMessage').textContent=state.providerConfigured?'Twilio is configured. Every substantive send still requires an authenticated person to approve it.':'Fictional inbound texting works locally. Configure Twilio credentials in the Atlas runtime before any real text can be sent.';}
