async function connectDemoEmail(provider){const status=byId('emailConnectionStatus');const message=byId('emailConnectionMessage');if(!['127.0.0.1','localhost'].includes(window.location.hostname)){message.textContent='The deployed OAuth connector must be configured before this provider can be authorized.';return;}document.querySelectorAll('[data-email-provider]').forEach(button=>button.disabled=true);status.textContent='Connecting demo';message.textContent='Creating fictional provider data without transmitting credentials…';try{let matter=pilotObjects.find(item=>item.dimension==='matter');if(!matter)matter=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`,{method:'POST',body:JSON.stringify({dimension:'matter',type:'civil',title:'Morgan v. Lakeside',state:{caseNumber:'DEMO-2026-101',clientName:'Taylor Morgan',status:'open'}})});const mailbox=provider==='google'?'demo@atlas-google.test':'demo@atlas-microsoft.test';for(const email of [{id:'status-request',from:'client@example.test',subject:'Request for case status',bodyText:'Please provide an update on the case when available.'},{id:'discovery-extension',from:'counsel@example.test',subject:'Discovery extension request',bodyText:'Please confirm whether your client agrees to a fourteen-day extension.'}])await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/ingestions/email`,{method:'POST',body:JSON.stringify({connector:`demo-${provider}`,externalId:email.id,matterId:matter.id,from:email.from,to:[mailbox],subject:email.subject,bodyText:email.bodyText,attachments:[]})});if(!pilotObjects.some(item=>item.type==='deadline'&&item.state?.externalSource?.provider===`demo-${provider}`))await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/objects`,{method:'POST',body:JSON.stringify({parentObjectId:matter.id,dimension:'operation',type:'deadline',title:'Discovery responses due',state:{scope:'matter',matterId:matter.id,date:new Date(Date.now()+5*86_400_000).toISOString(),status:'open',externalSource:{provider:`demo-${provider}`}}})});await loadPilotData();status.textContent='Demo connected';message.textContent=`Fictional ${provider==='google'?'Google Workspace':'Microsoft 365'} email and calendar data is now cataloged for this firm.`;renderCollection(activeCollection);}catch(error){status.textContent='Not connected';message.textContent=error.message;}finally{document.querySelectorAll('[data-email-provider]').forEach(button=>button.disabled=false);}}
function emailProviderLabel(provider){return provider==='google'?'Google Workspace':provider==='microsoft'?'Microsoft 365':provider;}
function renderEmailConnections(){const list=byId('emailConnections');list.replaceChildren();const connections=emailConnections.filter(item=>['google','microsoft'].includes(item.provider));byId('emailConnectionStatus').textContent=connections.length?`${connections.length} connected`:'Not connected';for(const connection of connections){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(connection.status)}</span><h3>${escape(emailProviderLabel(connection.provider))}</h3><p class="muted">Read-only email and calendar synchronization${connection.lastSyncedAt?` · Last synced ${escape(new Date(connection.lastSyncedAt).toLocaleString())}`:' · Awaiting first sync'}</p>`;const sync=document.createElement('button');sync.className='primary';sync.textContent='Sync now';sync.addEventListener('click',()=>syncEmailConnection(connection,sync));const disconnect=document.createElement('button');disconnect.className='danger';disconnect.textContent='Disconnect';disconnect.addEventListener('click',()=>disconnectEmailConnection(connection,disconnect));card.append(sync,document.createTextNode(' '),disconnect);list.append(card);}if(!connections.length)list.innerHTML='<div class="empty">No production mailbox is connected.</div>';}
async function loadEmailConnections(){if(!session)return;try{[emailProviders,emailConnections]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/providers`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections`)]);renderEmailConnections();const available=new Set(emailProviders.map(item=>item.name));document.querySelectorAll('[data-email-provider]').forEach(button=>{const configured=available.has(button.dataset.emailProvider);button.textContent=`${configured?'Connect':'Preview'} ${emailProviderLabel(button.dataset.emailProvider)}`;});if(emailConnections.some(item=>['google','microsoft'].includes(item.provider)))byId('emailConnectionMessage').textContent='Connected mail is synchronized read-only, cataloged as canonical firm activity, and routed through Atlas intelligence for attorney review.';}catch(error){byId('emailConnectionStatus').textContent='Unavailable';byId('emailConnectionMessage').textContent=error.message;}}
async function syncEmailConnection(connection,button){button.disabled=true;byId('emailConnectionMessage').textContent=`Synchronizing ${emailProviderLabel(connection.provider)}…`;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections/${encodeURIComponent(connection.id)}/sync`,{method:'POST'});byId('emailConnectionMessage').textContent=`Sync complete: ${result.imported} imported, ${result.updated} updated, ${result.tombstones??0} archived at the source.`;await loadPilotData();await loadEmailConnections();if(activeCollection)renderCollection(activeCollection);}catch(error){byId('emailConnectionMessage').textContent=error.message;}finally{button.disabled=false;}}
async function disconnectEmailConnection(connection,button){button.disabled=true;try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/connections/${encodeURIComponent(connection.id)}`,{method:'DELETE'});byId('emailConnectionMessage').textContent=`${emailProviderLabel(connection.provider)} disconnected. Existing Atlas records were preserved.`;await loadEmailConnections();}catch(error){byId('emailConnectionMessage').textContent=error.message;button.disabled=false;}}
async function connectEmailProvider(provider){const configured=emailProviders.some(item=>item.name===provider);if(!configured)return connectDemoEmail(provider);const buttons=document.querySelectorAll('[data-email-provider]');buttons.forEach(button=>button.disabled=true);byId('emailConnectionStatus').textContent='Authorizing';byId('emailConnectionMessage').textContent=`Opening ${emailProviderLabel(provider)} secure consent. Atlas never receives the mailbox password.`;try{const result=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/cms/${encodeURIComponent(provider)}/authorize`,{method:'POST',body:JSON.stringify({redirectUri:`${window.location.origin}/v1/cms/oauth/callback`})});const authorizationUrl=new URL(result.authorizationUrl);if(authorizationUrl.protocol!=='https:')throw new Error('The provider returned an insecure authorization URL.');const popup=window.open(authorizationUrl.href,'atlas-mailbox-authorization','popup,width=720,height=820,noopener,noreferrer');if(!popup)throw new Error('Allow the Atlas authorization popup, then try again.');byId('emailConnectionMessage').textContent=`Finish consent with ${emailProviderLabel(provider)} in the secure provider window. Return here afterward and Atlas will detect the connection.`;}catch(error){byId('emailConnectionStatus').textContent='Not connected';byId('emailConnectionMessage').textContent=error.message;}finally{buttons.forEach(button=>button.disabled=false);}}
document.querySelectorAll('[data-email-provider]').forEach(button=>button.addEventListener('click',()=>connectEmailProvider(button.dataset.emailProvider)));
window.addEventListener('focus',()=>{if(session&&['email','calendar'].includes(activeCollection))void loadEmailConnections();});
window.addEventListener('focus',()=>{if(!session)return;if(activeView==='migration')void loadMigration();if(activeView==='accounting')void loadAccounting();});
function renderFirmSecurity(events,sessions){const eventList=byId('securityEventList');eventList.replaceChildren();for(const event of events.slice(0,20)){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(event.outcome)}</span><h3>${escape(event.type.replaceAll('.',' '))}</h3><p class="muted">${escape(new Date(event.createdAt).toLocaleString())}${event.ipAddress?` · ${escape(event.ipAddress)}`:''}${event.details?.reason?` · ${escape(event.details.reason.replaceAll('_',' '))}`:''}</p>`;eventList.append(card);}if(!eventList.children.length)eventList.innerHTML='<div class="empty">No security activity has been recorded for this firm.</div>';const sessionList=byId('firmSessionList');sessionList.replaceChildren();byId('firmSessionCount').textContent=`${sessions.length} recorded`;for(const firmSession of sessions.slice(0,30)){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(firmSession.status)}${firmSession.current?' · current':''}</span><h3>${escape(firmSession.user?.name??firmSession.user?.email)}</h3><p class="muted">${escape(firmSession.user?.email)} · Started ${escape(new Date(firmSession.createdAt).toLocaleString())}</p>`;sessionList.append(card);}if(!sessionList.children.length)sessionList.innerHTML='<div class="empty">No firm sessions were returned.</div>';}
async function loadSecuritySettings(){if(!session)return;try{const mfa=await request('/v1/auth/mfa');byId('mfaStatus').textContent=mfa.enabled?'MFA enabled':mfa.pending?'Setup pending':'MFA not enabled';byId('mfaEnrollForm').classList.toggle('hidden',mfa.enabled);byId('mfaDisableForm').classList.toggle('hidden',!mfa.enabled);if(mfa.enabled)byId('mfaMessage').textContent=`${mfa.recoveryCodesRemaining} unused recovery code${mfa.recoveryCodesRemaining===1?'':'s'} remain.`;}catch(error){byId('mfaStatus').textContent='Unavailable';byId('mfaMessage').textContent=error.message;}try{const [events,sessions,policy]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/security/events?limit=100`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/security/sessions`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/security/policy`)]);byId('firmSecurityAdmin').classList.remove('hidden');byId('firmMfaRequired').checked=policy.requireMfa;byId('firmMfaPolicyStatus').textContent=policy.requireMfa?'Required':'Optional';renderFirmSecurity(events,sessions);byId('firmSecurityMessage').textContent='Security activity is append-only. Firm administrators can terminate every session during an incident.';}catch(error){byId('firmSecurityAdmin').classList.add('hidden');}}
function renderFirmMembers(members){const list=byId('memberList');list.replaceChildren();const active=members.filter(item=>item.active!==false).length;byId('memberCount').textContent=`${active} active seat${active===1?'':'s'}`;for(const member of members){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(member.role)} · ${member.active===false?'deactivated':'active'} · ${member.mfaEnabled?'MFA':'no MFA'}</span><h3>${escape(member.user?.name??member.userId)}</h3><p class="muted">${escape(member.user?.email??'Firm user')}${member.deactivationReason?` · ${escape(member.deactivationReason)}`:''}</p>`;if(member.role!=='owner'){const button=document.createElement('button');button.type='button';button.className=member.active===false?'primary':'danger';button.textContent=member.active===false?'Reactivate firm access':'Deactivate firm access';button.addEventListener('click',()=>setMembershipActive(member,member.active===false,button));card.append(button);}list.append(card);}if(!members.length)list.innerHTML='<div class="empty">No firm members were returned.</div>';}
async function setMembershipActive(member,active,button){button.disabled=true;try{const path=`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/memberships/${encodeURIComponent(member.userId)}/${active?'reactivate':'deactivate'}`;await request(path,{method:'POST',body:active?'{}':JSON.stringify({reason:'Deactivated by a firm administrator'})});await loadSettings();await loadSecuritySettings();}catch(error){byId('inviteError').textContent=error.message;button.disabled=false;}}
function renderFirmInvitations(invitations){const list=byId('invitationList');list.replaceChildren();for(const invitation of invitations.filter(item=>item.status==='pending')){const card=document.createElement('article');card.className='object-card';card.innerHTML=`<span class="pill">${escape(invitation.role)} · pending</span><h3>${escape(invitation.email)}</h3><p class="muted">Expires ${escape(new Date(invitation.expiresAt).toLocaleString())}</p>`;list.append(card);}if(!list.children.length)list.innerHTML='<div class="empty">No pending invitations.</div>';}
async function loadSettings(){try{const [subscription,members,invitations]=await Promise.all([request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/subscription`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/memberships`),request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/invitations`)]);byId('settingsSubscription').textContent=`${subscription.plan} · ${subscription.status} · ${members.length}/${subscription.seatLimit} seats`;renderFirmMembers(members);renderFirmInvitations(invitations);byId('inviteMemberForm').classList.remove('hidden');byId('inviteError').textContent='';}catch(error){byId('settingsSubscription').textContent='Member administration unavailable';byId('inviteMemberForm').classList.add('hidden');byId('inviteError').textContent=error.message;}}
byId('inviteMemberForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('inviteError').textContent='';byId('invitationLink').classList.add('hidden');try{const invitation=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/invitations`,{method:'POST',body:JSON.stringify({email:byId('inviteEmail').value,role:byId('inviteRole').value})});const link=`${window.location.origin}/?invite=${encodeURIComponent(invitation.invitationToken)}`;const output=byId('invitationLink');output.replaceChildren();const heading=document.createElement('strong');heading.textContent='One-time invitation link';const field=document.createElement('input');field.value=link;field.readOnly=true;field.setAttribute('aria-label','One-time invitation link');field.addEventListener('focus',()=>field.select());const copy=document.createElement('button');copy.type='button';copy.textContent='Copy link';copy.addEventListener('click',async()=>{try{await navigator.clipboard.writeText(link);copy.textContent='Copied';}catch{field.select();copy.textContent='Select and copy the link';}});output.append(heading,field,copy);output.classList.remove('hidden');event.target.reset();await loadSettings();}catch(error){byId('inviteError').textContent=error.message;}});
byId('mfaEnrollForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('mfaMessage').textContent='Creating encrypted authenticator enrollment…';try{const enrollment=await request('/v1/auth/mfa/enroll',{method:'POST',body:JSON.stringify({password:byId('mfaPassword').value})});byId('mfaSecret').value=enrollment.secret;byId('mfaRecoveryCodes').value=enrollment.recoveryCodes.join('\n');byId('mfaEnrollment').classList.remove('hidden');byId('mfaMessage').textContent='Save the recovery codes offline. They will not be displayed again.';byId('mfaConfirmCode').focus();}catch(error){byId('mfaMessage').textContent=error.message;}});
byId('mfaConfirmForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('mfaMessage').textContent='Verifying authenticator code…';try{await request('/v1/auth/mfa/confirm',{method:'POST',body:JSON.stringify({code:byId('mfaConfirmCode').value})});resetSignedOutUi();byId('loginError').textContent='MFA is enabled. Every session was closed; sign in with your password and current authenticator code.';byId('loginMfaCode').focus();}catch(error){byId('mfaMessage').textContent=error.message;}});
byId('mfaDisableForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('mfaMessage').textContent='Disabling MFA and closing sessions…';try{await request('/v1/auth/mfa',{method:'DELETE',body:JSON.stringify({password:byId('mfaDisablePassword').value,code:byId('mfaDisableCode').value})});resetSignedOutUi();byId('loginError').textContent='MFA was disabled and every session was closed. Sign in again.';}catch(error){byId('mfaMessage').textContent=error.message;}});
byId('socialConfigurationForm').addEventListener('submit',async(event)=>{event.preventDefault();const message=byId('socialConfigurationError');message.textContent='Saving attorney-controlled social preferences…';try{socialState=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/social-media/configuration`,{method:'POST',body:JSON.stringify({enabled:byId('socialEnabled').checked,networks:selectedSocialNetworks(),topics:socialTopics(),cadence:'manual',tone:byId('socialTone').value})});message.textContent=byId('socialEnabled').checked?'Social suggestions are enabled. Atlas will draft only when an attorney requests one.':'Social suggestions are disabled.';await loadSocial();}catch(error){message.textContent=error.message;}});
byId('socialSuggestionForm').addEventListener('submit',async(event)=>{event.preventDefault();const message=byId('socialSuggestionError');const button=event.target.querySelector('button');button.disabled=true;message.textContent='Atlas is preparing an internal draft for attorney review…';try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/social-media/suggestions`,{method:'POST',body:JSON.stringify({topic:byId('socialSuggestionTopic').value})});event.target.reset();message.textContent='Suggestion created. It is now in While You Were Gone for attorney review; nothing was published.';await loadPilotData();await loadSocial();}catch(error){message.textContent=error.message;}finally{button.disabled=false;}});
byId('refreshSecurity').addEventListener('click',()=>void loadSecuritySettings());
byId('firmMfaPolicyForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('firmSecurityMessage').textContent='Saving firm MFA policy…';try{const policy=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/security/policy`,{method:'PATCH',body:JSON.stringify({requireMfa:byId('firmMfaRequired').checked})});byId('firmMfaPolicyStatus').textContent=policy.requireMfa?'Required':'Optional';byId('firmSecurityMessage').textContent=policy.requireMfa?'Firm-wide MFA is required. Members without MFA are blocked from firm work until enrollment.':'Firm-wide MFA is optional.';await loadSettings();}catch(error){byId('firmSecurityMessage').textContent=error.message;await loadSecuritySettings();}});
byId('firmExportForm').addEventListener('submit',async(event)=>{event.preventDefault();const message=byId('firmExportMessage');message.textContent='Preparing verified firm export…';try{const exported=await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/exports`,{method:'POST',body:JSON.stringify({confirmation:byId('firmExportConfirmation').value})});const blob=new Blob([JSON.stringify(exported,null,2)],{type:'application/json'});const link=document.createElement('a');link.href=URL.createObjectURL(blob);link.download=`atlas-firm-export-${new Date().toISOString().slice(0,10)}.json`;link.click();URL.revokeObjectURL(link.href);byId('firmExportConfirmation').value='';message.textContent=`Export ready. SHA-256: ${exported.manifest.digest}`;}catch(error){message.textContent=error.message;}});
byId('firmSignOutForm').addEventListener('submit',async(event)=>{event.preventDefault();if(byId('firmSignOutConfirmation').value!=='SIGN OUT ALL'){byId('firmSecurityMessage').textContent='Type SIGN OUT ALL exactly to confirm the emergency action.';return;}try{await request(`/v1/workspaces/${encodeURIComponent(session.workspaceId)}/security/sign-out-all`,{method:'POST',body:'{}'});resetSignedOutUi();byId('loginError').textContent='Every firm session was revoked. Sign in again.';}catch(error){byId('firmSecurityMessage').textContent=error.message;}});
byId('invitationForm').addEventListener('submit',async(event)=>{event.preventDefault();byId('invitationError').textContent='';try{session={base:byId('apiBase').value.replace(/\/$/,''),workspaceId:null,token:null,refreshToken:null};const result=await request('/v1/auth/invitations/accept',{method:'POST',body:JSON.stringify({invitationToken:byId('invitationToken').value,name:byId('invitationName').value,password:byId('invitationPassword').value})});session.workspaceId=result.workspace.id;session.token=result.accessToken;session.refreshToken=result.refreshToken;byId('workspaceId').value=result.workspace.id;history.replaceState(null,'',window.location.pathname);await enterWorkspace();}catch(error){session=null;clearStoredSession();byId('invitationError').textContent=error.message;}});
byId('twinToggle').addEventListener('click',()=>{const collapsed=byId('twinDock').classList.toggle('collapsed');const toggle=byId('twinToggle');toggle.setAttribute('aria-expanded',String(!collapsed));toggle.setAttribute('aria-label',collapsed?'Open Atlas':'Close Atlas');if(!collapsed)byId('twinInput').focus();});byId('twinForm').addEventListener('submit',event=>{event.preventDefault();submitTwinCommand(byId('twinInput').value);});
byId('settingsButton').addEventListener('click',()=>showView('settings'));
byId('viewAllEvents').addEventListener('click',()=>showView('events'));byId('firmEventSearch').addEventListener('input',renderFirmEvents);
byId('openCasesMetric').addEventListener('click',()=>showView('matters'));byId('openTasksMetric').addEventListener('click',()=>showView('tasks'));byId('reviewDeadlinesMetric').addEventListener('click',()=>routeHomeCommand('Review every approaching or missed deadline across the firm, explain the risk, and recommend the next work to prepare.'));byId('openReviewMetric').addEventListener('click',()=>byId('reviewInbox').scrollIntoView({behavior:'smooth',block:'start'}));
byId('commandForm').addEventListener('submit',(event)=>{event.preventDefault();routeHomeCommand(byId('commandInput').value);});document.querySelectorAll('[data-prompt]').forEach((button)=>button.addEventListener('click',()=>routeHomeCommand(button.dataset.prompt)));byId('workspaceAssistantForm').addEventListener('submit',(event)=>{event.preventDefault();submitWorkspaceCommand(byId('workspaceAssistantInput').value);});document.querySelectorAll('[data-workspace-prompt]').forEach(button=>button.addEventListener('click',()=>submitWorkspaceCommand(button.dataset.workspacePrompt)));byId('workspaceSearch').addEventListener('input',renderWorkspaceWork);byId('workspaceFilter').addEventListener('change',renderWorkspaceWork);document.querySelectorAll('.nav button').forEach((button)=>button.addEventListener('click',()=>showView(button.dataset.view)));submitChatOnEnter('commandInput','commandForm');submitChatOnEnter('workspaceAssistantInput','workspaceAssistantForm');submitChatOnEnter('twinInput','twinForm');
function resetSignedOutUi(){document.body.classList.remove('atlas-authenticated');session=null;conversationId=null;workspaceActions=[];workspaceAwareness=[];socialState=null;emailProviders=[];emailConnections=[];smsState=null;clearStoredSession();byId('home').classList.add('hidden');byId('onboarding').classList.add('hidden');byId('login').classList.remove('hidden');byId('feed').replaceChildren();byId('transcript').replaceChildren();byId('workspaceAssistantTranscript').replaceChildren();byId('twinTranscript').replaceChildren();byId('commandStatus').textContent='';byId('workspaceAssistantStatus').textContent='';byId('twinStatus').textContent='';}
async function signOut(){const refreshToken=session?.refreshToken;try{if(refreshToken)await fetch(`${session.base}/v1/auth/logout`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({refreshToken})});}finally{resetSignedOutUi();}}
async function restoreStoredSession(){let stored;try{stored=JSON.parse(sessionStorage.getItem(sessionStorageKey)??'null');if(!stored?.token||!stored?.refreshToken||!stored?.workspaceId)return;const base=new URL(stored.base??window.location.origin);if(!['http:','https:'].includes(base.protocol))throw new Error('Invalid stored Atlas origin');session={base:base.origin,token:stored.token,refreshToken:stored.refreshToken,workspaceId:stored.workspaceId};byId('apiBase').value=session.base;byId('workspaceId').value=session.workspaceId;await enterWorkspace();}catch(error){resetSignedOutUi();byId('loginError').textContent='Your saved Atlas session ended. Sign in again.';}}
byId('signOut').addEventListener('click',()=>void signOut());
const invitationTokenFromUrl=new URLSearchParams(window.location.search).get('invite');if(invitationTokenFromUrl){byId('invitationToken').value=invitationTokenFromUrl;byId('invitationPanel').open=true;byId('invitationName').focus();}
